#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>
#include "yfs.h"
#include "cache.h"

int NUM_INODES;
int NUM_BLOCKS;
int FIRST_DATA_BLOCK;

static char block_bitmap[NUMSECTORS / 8 + 1];
static char inode_bitmap[1024 / 8 + 1];

static void set_bit(char *bitmap, int bit, int max_bits) {
    if (bit < 0 || bit >= max_bits) return;
    bitmap[bit / 8] |= (1 << (bit % 8));
}
static void clear_bit(char *bitmap, int bit, int max_bits) {
    if (bit < 0 || bit >= max_bits) return;
    bitmap[bit / 8] &= ~(1 << (bit % 8));
}
static int get_bit(char *bitmap, int bit, int max_bits) {
    if (bit < 0 || bit >= max_bits) return 0;
    return (bitmap[bit / 8] >> (bit % 8)) & 1;
}

static int alloc_inode() {
    int i;
    for (i = 1; i <= NUM_INODES; i++) {
        if (!get_bit(inode_bitmap, i, 1024)) {
            set_bit(inode_bitmap, i, 1024);
            struct cache_inode *ci = get_inode(i);
            if (ci) { ci->inode.reuse++; ci->dirty = 1; return i; }
        }
    }
    return ERROR;
}

static void free_inode(int inum) {
    if (inum <= 0 || inum > NUM_INODES) return;
    struct cache_inode *ci = get_inode(inum);
    if (ci) { ci->inode.type = INODE_FREE; ci->dirty = 1; }
    clear_bit(inode_bitmap, inum, 1024);
}

static int alloc_block() {
    int i;
    for (i = FIRST_DATA_BLOCK; i < NUM_BLOCKS; i++) {
        if (!get_bit(block_bitmap, i, NUMSECTORS)) {
            set_bit(block_bitmap, i, NUMSECTORS);
            struct cache_block *cb = get_block(i);
            if (cb) { memset(cb->data, 0, BLOCKSIZE); cb->dirty = 1; return i; }
        }
    }
    return ERROR;
}

static void free_block(int blocknum) {
    if (blocknum < FIRST_DATA_BLOCK || blocknum >= NUM_BLOCKS) return;
    clear_bit(block_bitmap, blocknum, NUMSECTORS);
}

static void handle_open(int pid, yfs_msg_t *msg);
static void handle_create(int pid, yfs_msg_t *msg);
static void handle_read(int pid, yfs_msg_t *msg);
static void handle_write(int pid, yfs_msg_t *msg);
static void handle_seek(int pid, yfs_msg_t *msg);
static void handle_link(int pid, yfs_msg_t *msg);
static void handle_unlink(int pid, yfs_msg_t *msg);
static void handle_symlink(int pid, yfs_msg_t *msg);
static void handle_readlink(int pid, yfs_msg_t *msg);
static void handle_mkdir(int pid, yfs_msg_t *msg);
static void handle_rmdir(int pid, yfs_msg_t *msg);
static void handle_chdir(int pid, yfs_msg_t *msg);
static void handle_stat(int pid, yfs_msg_t *msg);

static int is_dot(char *name) { return (name[0] == '.' && (DIRNAMELEN == 1 || name[1] == '\0')); }
static int is_dotdot(char *name) { return (name[0] == '.' && name[1] == '.' && (DIRNAMELEN == 2 || name[2] == '\0')); }

static int find_in_dir(int dir_inum, char *name, int name_len) {
    if (name_len > DIRNAMELEN) return 0;
    struct cache_inode *ci = get_inode(dir_inum);
    if (!ci || ci->inode.type != INODE_DIRECTORY) return 0;
    int num_entries = ci->inode.size / sizeof(struct dir_entry), i;
    for (i = 0; i < num_entries; i++) {
        int block_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, offset = (i * sizeof(struct dir_entry)) % BLOCKSIZE, blocknum = 0;
        if (block_idx < NUM_DIRECT) blocknum = ci->inode.direct[block_idx];
        else if (ci->inode.indirect != 0) {
            struct cache_block *icb = get_block(ci->inode.indirect);
            if (icb) blocknum = ((int *)icb->data)[block_idx - NUM_DIRECT];
        }
        if (blocknum == 0) continue;
        struct cache_block *cb = get_block(blocknum);
        if (!cb) continue;
        struct dir_entry *de = (struct dir_entry *)(cb->data + offset);
        if (de->inum != 0) {
            if (name_len == DIRNAMELEN) { if (strncmp(de->name, name, DIRNAMELEN) == 0) return de->inum; }
            else if (strncmp(de->name, name, name_len) == 0 && (name_len == DIRNAMELEN || de->name[name_len] == '\0')) return de->inum;
        }
    }
    return 0;
}

static int get_block_for_offset(struct cache_inode *ci, int offset, int alloc) {
    int block_idx = offset / BLOCKSIZE;
    if (block_idx < NUM_DIRECT) {
        if (ci->inode.direct[block_idx] == 0 && alloc) {
            ci->inode.direct[block_idx] = alloc_block();
            if (ci->inode.direct[block_idx] != ERROR) ci->dirty = 1;
        }
        return ci->inode.direct[block_idx];
    } else {
        block_idx -= NUM_DIRECT;
        if (block_idx >= (int)(BLOCKSIZE / sizeof(int))) return ERROR;
        if (ci->inode.indirect == 0) {
            if (!alloc) return 0;
            ci->inode.indirect = alloc_block();
            if (ci->inode.indirect == ERROR) return ERROR;
            ci->dirty = 1;
        }
        struct cache_block *icb = get_block(ci->inode.indirect);
        if (!icb) return ERROR;
        int *ind = (int *)icb->data;
        if (ind[block_idx] == 0 && alloc) {
            ind[block_idx] = alloc_block();
            if (ind[block_idx] != ERROR) icb->dirty = 1;
        }
        return ind[block_idx];
    }
}

static int resolve_path_internal(int pid, int curr_dir_inum, char *path, int *parent_inum, char *last_component, int depth, int follow);

static int resolve_symlink(int pid, int dir_inum, int sym_inum, int depth) {
    if (depth >= MAXSYMLINKS) return ERROR;
    struct cache_inode *ci = get_inode(sym_inum);
    if (!ci || ci->inode.type != INODE_SYMLINK) return ERROR;
    char target[MAXPATHNAMELEN]; int to_read = ci->inode.size, br = 0;
    if (to_read >= MAXPATHNAMELEN) to_read = MAXPATHNAMELEN - 1;
    while (br < to_read) {
        int bnum = get_block_for_offset(ci, br, 0), off = br % BLOCKSIZE, n = BLOCKSIZE - off;
        if (bnum <= 0) break;
        if (n > to_read - br) n = to_read - br;
        struct cache_block *cb = get_block(bnum);
        if (!cb) break;
        memcpy(target + br, cb->data + off, n); br += n;
    }
    target[br] = '\0';
    return resolve_path_internal(pid, dir_inum, target, NULL, NULL, depth + 1, 1);
}

static int resolve_path_internal(int pid, int curr_dir_inum, char *path, int *parent_inum, char *last_component, int depth, int follow) {
    if (path == NULL || path[0] == '\0') return ERROR;
    int inum = (path[0] == '/') ? ROOTINODE : curr_dir_inum;
    if (parent_inum) *parent_inum = inum;
    if (last_component) strcpy(last_component, ".");
    char path_copy[MAXPATHNAMELEN]; strncpy(path_copy, path, MAXPATHNAMELEN); path_copy[MAXPATHNAMELEN-1] = '\0';
    char *curr = path_copy; while (*curr == '/') curr++;
    while (*curr != '\0') {
        char *next = strchr(curr, '/'); if (next) *next = '\0';
        if (parent_inum) *parent_inum = inum;
        if (last_component) { strncpy(last_component, curr, DIRNAMELEN); if (strlen(curr) < DIRNAMELEN) last_component[strlen(curr)] = '\0'; }
        int next_inum = find_in_dir(inum, curr, strlen(curr));
        if (!next_inum) {
            char *p = next ? next + 1 : NULL; while (p && *p == '/') p++;
            if (next == NULL || p == NULL || *p == '\0') return 0;
            return ERROR;
        }
        struct cache_inode *next_ci = get_inode(next_inum);
        if (next_ci && next_ci->inode.type == INODE_SYMLINK) {
            int is_last = (next == NULL); if (!is_last) { char *p = next + 1; while (*p == '/') p++; if (*p == '\0') is_last = 1; }
            if (!is_last || follow) { next_inum = resolve_symlink(pid, inum, next_inum, depth); if (next_inum == ERROR) return ERROR; }
        }
        if (next != NULL) {
            char *p = next + 1; while (*p == '/') p++;
            if (*p != '\0') {
                struct cache_inode *ci = get_inode(next_inum);
                if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;
                inum = next_inum; curr = p;
            } else { inum = next_inum; break; }
        } else { inum = next_inum; break; }
    }
    return inum;
}

static int resolve_path(int pid, int curr_dir_inum, char *path, int path_len, int *parent_inum, char *last_component, int follow) {
    if (path_len <= 0 || path_len >= MAXPATHNAMELEN) return ERROR;
    char local_path[MAXPATHNAMELEN]; if (CopyFrom(pid, local_path, path, path_len) == ERROR) return ERROR;
    local_path[path_len] = '\0';
    char cp[MAXPATHNAMELEN]; strcpy(cp, local_path); char *c = strtok(cp, "/");
    while (c) { if (strlen(c) > DIRNAMELEN) return ERROR; c = strtok(NULL, "/"); }
    if (path_len > 1 && local_path[path_len-1] == '/') {
        if (path_len + 1 < MAXPATHNAMELEN) { local_path[path_len] = '.'; local_path[path_len+1] = '\0'; }
    }
    return resolve_path_internal(pid, curr_dir_inum, local_path, parent_inum, last_component, 0, follow);
}

static void truncate_inode(struct cache_inode *ci) {
    int i, j;
    for (i = 0; i < NUM_DIRECT; i++) { if (ci->inode.direct[i] != 0) { free_block(ci->inode.direct[i]); ci->inode.direct[i] = 0; } }
    if (ci->inode.indirect != 0) {
        struct cache_block *cb = get_block(ci->inode.indirect);
        if (cb) {
            int *ind = (int *)cb->data;
            for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) if (ind[j] != 0) free_block(ind[j]);
        }
        free_block(ci->inode.indirect); ci->inode.indirect = 0;
    }
    ci->inode.size = 0; ci->dirty = 1;
}

static int add_to_dir(int dir_inum, int inum, char *name) {
    struct cache_inode *ci = get_inode(dir_inum); if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;
    int num_entries = ci->inode.size / sizeof(struct dir_entry), i, found_free = 0, target_block = 0, target_offset = 0;
    for (i = 0; i < num_entries; i++) {
        int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
        if (b_idx < NUM_DIRECT) bnum = ci->inode.direct[b_idx];
        else if (ci->inode.indirect != 0) {
            struct cache_block *icb = get_block(ci->inode.indirect);
            if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT];
        }
        if (bnum == 0) continue;
        struct cache_block *cb = get_block(bnum); if (!cb) continue;
        struct dir_entry *de = (struct dir_entry *)(cb->data + off);
        if (de->inum == 0) { found_free = 1; target_block = bnum; target_offset = off; break; }
    }
    if (!found_free) {
        int b_idx = (num_entries * sizeof(struct dir_entry)) / BLOCKSIZE, off = (num_entries * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
        if (b_idx < NUM_DIRECT) {
            if (ci->inode.direct[b_idx] == 0) { ci->inode.direct[b_idx] = alloc_block(); if (ci->inode.direct[b_idx] == ERROR) return ERROR; }
            bnum = ci->inode.direct[b_idx];
        } else {
            if (ci->inode.indirect == 0) { ci->inode.indirect = alloc_block(); if (ci->inode.indirect == ERROR) return ERROR; }
            struct cache_block *icb = get_block(ci->inode.indirect); if (!icb) return ERROR;
            int *ind = (int *)icb->data;
            if (ind[b_idx - NUM_DIRECT] == 0) { ind[b_idx - NUM_DIRECT] = alloc_block(); if (ind[b_idx - NUM_DIRECT] == ERROR) return ERROR; icb->dirty = 1; }
            bnum = ind[b_idx - NUM_DIRECT];
        }
        target_block = bnum; target_offset = off; ci->inode.size += sizeof(struct dir_entry); ci->dirty = 1;
    }
    struct cache_block *cb = get_block(target_block); if (!cb) return ERROR;
    struct dir_entry *de = (struct dir_entry *)(cb->data + target_offset); de->inum = inum; strncpy(de->name, name, DIRNAMELEN); cb->dirty = 1;
    return 0;
}

static int is_dir_empty(int inum) {
    struct cache_inode *ci = get_inode(inum); if (!ci) return 0;
    int num_entries = ci->inode.size / sizeof(struct dir_entry), i;
    for (i = 0; i < num_entries; i++) {
        int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
        if (b_idx < NUM_DIRECT) bnum = ci->inode.direct[b_idx];
        else if (ci->inode.indirect != 0) {
            struct cache_block *icb = get_block(ci->inode.indirect);
            if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT];
        }
        if (bnum == 0) continue;
        struct cache_block *cb = get_block(bnum); if (!cb) continue;
        struct dir_entry *de = (struct dir_entry *)(cb->data + off);
        if (de->inum != 0 && !is_dot(de->name) && !is_dotdot(de->name)) return 0;
    }
    return 1;
}

static void handle_open(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL, 1);
    if (inum <= 0) msg->common.type = ERROR;
    else { struct cache_inode *ci = get_inode(inum); if (!ci) msg->common.type = ERROR; else { msg->common.inum = inum; msg->common.reuse = ci->inode.reuse; msg->common.val2 = (ci->inode.type == INODE_DIRECTORY); } }
    Reply(msg, pid);
}

static void handle_create(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 1);
    if (inum > 0) { struct cache_inode *ci = get_inode(inum); if (!ci || ci->inode.type == INODE_DIRECTORY) msg->common.type = ERROR; else { truncate_inode(ci); msg->common.inum = inum; msg->common.reuse = ci->inode.reuse; } }
    else if (inum == 0) {
        struct cache_inode *pci = get_inode(p_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) msg->common.type = ERROR;
            else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_REGULAR; nci->inode.nlink = 1; nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
                if (add_to_dir(p_inum, new_inum, last) == ERROR) { free_inode(new_inum); msg->common.type = ERROR; }
                else { msg->common.inum = new_inum; msg->common.reuse = nci->inode.reuse; }
            }
        }
    } else msg->common.type = ERROR;
    Reply(msg, pid);
}

static void handle_read(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse) { msg->common.type = ERROR; Reply(msg, pid); return; }
    int pos = msg->common.val2, size = msg->common.val1; if (pos >= ci->inode.size) { msg->common.val1 = 0; Reply(msg, pid); return; }
    if (pos + size > ci->inode.size) size = ci->inode.size - pos;
    int br = 0;
    while (br < size) {
        int curr_pos = pos + br, bnum = get_block_for_offset(ci, curr_pos, 0);
        if (bnum == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; }
        int off = curr_pos % BLOCKSIZE, tr = BLOCKSIZE - off; if (tr > size - br) tr = size - br;
        if (bnum == 0) { char zeros[BLOCKSIZE]; memset(zeros, 0, tr); if (CopyTo(pid, (char *)msg->common.ptr1 + br, zeros, tr) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; } }
        else { struct cache_block *cb = get_block(bnum); if (!cb || CopyTo(pid, (char *)msg->common.ptr1 + br, cb->data + off, tr) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; } }
        br += tr;
    }
    msg->common.val1 = br; Reply(msg, pid);
}

static void handle_write(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse || ci->inode.type == INODE_DIRECTORY) { msg->common.type = ERROR; Reply(msg, pid); return; }
    int pos = msg->common.val2, size = msg->common.val1, bw = 0;
    while (bw < size) {
        int curr_pos = pos + bw, bnum = get_block_for_offset(ci, curr_pos, 1);
        if (bnum <= 0) { msg->common.type = ERROR; Reply(msg, pid); return; }
        int off = curr_pos % BLOCKSIZE, tw = BLOCKSIZE - off; if (tw > size - bw) tw = size - bw;
        struct cache_block *cb = get_block(bnum);
        if (!cb || CopyFrom(pid, cb->data + off, (char *)msg->common.ptr1 + bw, tw) == ERROR) { msg->common.type = ERROR; Reply(msg, pid); return; }
        cb->dirty = 1; bw += tw;
    }
    if (pos + bw > ci->inode.size) { ci->inode.size = pos + bw; ci->dirty = 1; }
    msg->common.val1 = bw; Reply(msg, pid);
}

static void handle_seek(int pid, yfs_msg_t *msg) {
    struct cache_inode *ci = get_inode(msg->common.inum);
    if (!ci || ci->inode.reuse != msg->common.reuse) msg->common.type = ERROR;
    else {
        int np;
        if (msg->common.val2 == SEEK_SET) np = msg->common.val1;
        else if (msg->common.val2 == SEEK_CUR) np = msg->common.val3 + msg->common.val1;
        else if (msg->common.val2 == SEEK_END) np = ci->inode.size + msg->common.val1;
        else { msg->common.type = ERROR; Reply(msg, pid); return; }
        if (np < 0) msg->common.type = ERROR; else msg->common.val1 = np;
    }
    Reply(msg, pid);
}

static void handle_stat(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (inum <= 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum); if (!ci) msg->two_ptr.type = ERROR;
        else { struct Stat st; st.inum = inum; st.type = ci->inode.type; st.size = ci->inode.size; st.nlink = ci->inode.nlink; if (CopyTo(pid, msg->two_ptr.ptr2, &st, sizeof(struct Stat)) == ERROR) msg->two_ptr.type = ERROR; }
    }
    Reply(msg, pid);
}

static void handle_chdir(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL, 1);
    if (inum <= 0) msg->common.type = ERROR;
    else { struct cache_inode *ci = get_inode(inum); if (!ci || ci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR; else msg->common.inum = inum; }
    Reply(msg, pid);
}

static void handle_mkdir(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 0);
    if (inum != 0) msg->common.type = ERROR;
    else {
        struct cache_inode *pci = get_inode(p_inum);
        if (!pci || pci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            int new_inum = alloc_inode();
            if (new_inum == ERROR) msg->common.type = ERROR;
            else {
                struct cache_inode *nci = get_inode(new_inum);
                nci->inode.type = INODE_DIRECTORY; nci->inode.nlink = 2; nci->inode.size = 0;
                memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
                if (add_to_dir(new_inum, new_inum, ".") == ERROR || add_to_dir(new_inum, p_inum, "..") == ERROR || add_to_dir(p_inum, new_inum, last) == ERROR) msg->common.type = ERROR;
                else { pci->inode.nlink++; pci->dirty = 1; msg->common.inum = new_inum; }
            }
        }
    }
    Reply(msg, pid);
}

static void handle_rmdir(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 0);
    if (inum <= 0 || inum == ROOTINODE || is_dot(last) || is_dotdot(last)) msg->common.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (!ci || ci->inode.type != INODE_DIRECTORY || !is_dir_empty(inum)) msg->common.type = ERROR;
        else {
            struct cache_inode *pci = get_inode(p_inum); if (!pci) { msg->common.type = ERROR; Reply(msg, pid); return; }
            int num = pci->inode.size / sizeof(struct dir_entry), i;
            for (i = 0; i < num; i++) {
                int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
                if (b_idx < NUM_DIRECT) bnum = pci->inode.direct[b_idx];
                else if (pci->inode.indirect != 0) { struct cache_block *icb = get_block(pci->inode.indirect); if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT]; }
                if (bnum == 0) continue;
                struct cache_block *cb = get_block(bnum); if (!cb) continue;
                struct dir_entry *de = (struct dir_entry *)(cb->data + off); if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
            }
            pci->inode.nlink--; pci->dirty = 1; truncate_inode(ci); free_inode(inum);
        }
    }
    Reply(msg, pid);
}

static void handle_link(int pid, yfs_msg_t *msg) {
    int old_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (old_inum <= 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *oci = get_inode(old_inum);
        if (!oci || oci->inode.type == INODE_DIRECTORY) msg->two_ptr.type = ERROR;
        else {
            int p_inum; char last[DIRNAMELEN + 1];
            int n_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
            if (n_inum != 0) msg->two_ptr.type = ERROR;
            else { if (add_to_dir(p_inum, old_inum, last) == ERROR) msg->two_ptr.type = ERROR; else { oci->inode.nlink++; oci->dirty = 1; } }
        }
    }
    Reply(msg, pid);
}

static void handle_unlink(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 0);
    if (inum <= 0) msg->common.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (!ci || ci->inode.type == INODE_DIRECTORY) msg->common.type = ERROR;
        else {
            struct cache_inode *pci = get_inode(p_inum); if (!pci) { msg->common.type = ERROR; Reply(msg, pid); return; }
            int num = pci->inode.size / sizeof(struct dir_entry), i;
            for (i = 0; i < num; i++) {
                int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
                if (b_idx < NUM_DIRECT) bnum = pci->inode.direct[b_idx];
                else if (pci->inode.indirect != 0) { struct cache_block *icb = get_block(pci->inode.indirect); if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT]; }
                if (bnum == 0) continue;
                struct cache_block *cb = get_block(bnum); if (!cb) continue;
                struct dir_entry *de = (struct dir_entry *)(cb->data + off); if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
            }
            ci->inode.nlink--; ci->dirty = 1; if (ci->inode.nlink == 0) { truncate_inode(ci); free_inode(inum); }
        }
    }
    Reply(msg, pid);
}

static void handle_symlink(int pid, yfs_msg_t *msg) {
    int p_inum; char last[DIRNAMELEN + 1];
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
    if (inum != 0) msg->two_ptr.type = ERROR;
    else {
        int new_inum = alloc_inode();
        if (new_inum == ERROR) msg->two_ptr.type = ERROR;
        else {
            struct cache_inode *nci = get_inode(new_inum);
            nci->inode.type = INODE_SYMLINK; nci->inode.nlink = 1; nci->inode.size = msg->two_ptr.val1;
            memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
            char target[MAXPATHNAMELEN]; CopyFrom(pid, target, msg->two_ptr.ptr1, msg->two_ptr.val1);
            int bw = 0;
            while (bw < (int)msg->two_ptr.val1) {
                int bnum = get_block_for_offset(nci, bw, 1), off = bw % BLOCKSIZE, tw = BLOCKSIZE - off;
                if (bnum <= 0) break;
                if (tw > (int)msg->two_ptr.val1 - bw) tw = msg->two_ptr.val1 - bw;
                struct cache_block *cb = get_block(bnum); if (!cb) break;
                memcpy(cb->data + off, target + bw, tw); cb->dirty = 1; bw += tw;
            }
            if (add_to_dir(p_inum, new_inum, last) == ERROR) { truncate_inode(nci); free_inode(new_inum); msg->two_ptr.type = ERROR; }
        }
    }
    Reply(msg, pid);
}

static void handle_readlink(int pid, yfs_msg_t *msg) {
    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
    if (inum <= 0) msg->two_ptr.type = ERROR;
    else {
        struct cache_inode *ci = get_inode(inum);
        if (!ci || ci->inode.type != INODE_SYMLINK) msg->two_ptr.type = ERROR;
        else {
            int tr = ci->inode.size; if (tr > msg->two_ptr.val2) tr = msg->two_ptr.val2;
            char target[MAXPATHNAMELEN]; int br = 0;
            while (br < tr) {
                int bnum = get_block_for_offset(ci, br, 0), off = br % BLOCKSIZE, n = BLOCKSIZE - off;
                if (bnum <= 0) break;
                if (n > tr - br) n = tr - br;
                struct cache_block *cb = get_block(bnum); if (!cb) break;
                memcpy(target + br, cb->data + off, n); br += n;
            }
            if (CopyTo(pid, msg->two_ptr.ptr2, target, tr) == ERROR) msg->two_ptr.type = ERROR;
            else msg->two_ptr.val1 = tr;
        }
    }
    Reply(msg, pid);
}

int main(int argc, char **argv) {
    char buf[SECTORSIZE]; if (ReadSector(1, buf) == ERROR) Exit(1);
    struct fs_header *header = (struct fs_header *)buf;
    NUM_BLOCKS = header->num_blocks; NUM_INODES = header->num_inodes;
    FIRST_DATA_BLOCK = 1 + (NUM_INODES / INODES_PER_BLOCK + 1);
    init_cache(); memset(block_bitmap, 0, sizeof(block_bitmap)); memset(inode_bitmap, 0, sizeof(inode_bitmap));
    int i, j;
    for (i = 1; i <= NUM_INODES; i++) {
        struct cache_inode *ci = get_inode(i);
        if (ci && ci->inode.type != INODE_FREE) {
            set_bit(inode_bitmap, i, 1024);
            for (j = 0; j < NUM_DIRECT; j++) if (ci->inode.direct[j] != 0) set_bit(block_bitmap, ci->inode.direct[j], NUMSECTORS);
            if (ci->inode.indirect != 0) {
                set_bit(block_bitmap, ci->inode.indirect, NUMSECTORS);
                struct cache_block *cb = get_block(ci->inode.indirect);
                if (cb) {
                    int *ind = (int *)cb->data;
                    for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) if (ind[j] != 0) set_bit(block_bitmap, ind[j], NUMSECTORS);
                }
            }
        }
    }
    if (Register(FILE_SERVER) == ERROR) Exit(1);
    if (argc > 1) { int pid = Fork(); if (pid == 0) { Exec(argv[1], argv + 1); Exit(1); } }
    while (1) {
        yfs_msg_t msg; int sender_pid = Receive(&msg); if (sender_pid <= 0) break;
        switch (msg.common.type) {
            case YFS_OPEN: handle_open(sender_pid, &msg); break;
            case YFS_CREATE: handle_create(sender_pid, &msg); break;
            case YFS_READ: handle_read(sender_pid, &msg); break;
            case YFS_WRITE: handle_write(sender_pid, &msg); break;
            case YFS_SEEK: handle_seek(sender_pid, &msg); break;
            case YFS_LINK: handle_link(sender_pid, &msg); break;
            case YFS_UNLINK: handle_unlink(sender_pid, &msg); break;
            case YFS_SYMLINK: handle_symlink(sender_pid, &msg); break;
            case YFS_READLINK: handle_readlink(sender_pid, &msg); break;
            case YFS_MKDIR: handle_mkdir(sender_pid, &msg); break;
            case YFS_RMDIR: handle_rmdir(sender_pid, &msg); break;
            case YFS_CHDIR: handle_chdir(sender_pid, &msg); break;
            case YFS_STAT: handle_stat(sender_pid, &msg); break;
            case YFS_SYNC: sync_cache(); Reply(&msg, sender_pid); break;
            case YFS_SHUTDOWN: sync_cache(); Reply(&msg, sender_pid); Exit(0);
            default: msg.common.type = ERROR; Reply(&msg, sender_pid);
        }
    }
    return 0;
}

