struct fd_entry {
    int inum;
    int reuse;
    int pos;
    int is_used;
    int is_dir;
};

static struct fd_entry fd_table[MAX_OPEN_FILES];
static int curr_dir_inum = ROOTINODE;
static int initialized = 0;

static void init_iolib() {
    if (!initialized) {
        int i;
        for (i = 0; i < MAX_OPEN_FILES; i++) {
            fd_table[i].is_used = 0;
        }
        curr_dir_inum = ROOTINODE;
        initialized = 1;
    }
}

int Open(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_OPEN;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].is_used) {
            fd_table[i].inum = msg.common.inum;
            fd_table[i].reuse = msg.common.reuse;
            fd_table[i].pos = 0;
            fd_table[i].is_used = 1;
            fd_table[i].is_dir = msg.common.val2; /* Server should return if it's a dir */
            return i;
        }
    }
    return ERROR;
}

int Close(int fd) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;

    fd_table[fd].is_used = 0;
    return 0;
}

int Create(char *pathname) {
    init_iolib();
    if (pathname == NULL) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_CREATE;
    msg.common.inum = curr_dir_inum;
    msg.common.ptr1 = pathname;
    msg.common.val1 = strlen(pathname);

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].is_used) {
            fd_table[i].inum = msg.common.inum;
            fd_table[i].reuse = msg.common.reuse;
            fd_table[i].pos = 0;
            fd_table[i].is_used = 1;
            fd_table[i].is_dir = 0; /* Created file is never a directory */
            return i;
        }
    }
    return ERROR;
}

int Read(int fd, void *buf, int size) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_READ;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = size;
    msg.common.val2 = fd_table[fd].pos;
    msg.common.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos += msg.common.val1;
    return msg.common.val1;
}

int Write(int fd, void *buf, int size) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;
    if (fd_table[fd].is_dir) return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_WRITE;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = size;
    msg.common.val2 = fd_table[fd].pos;
    msg.common.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos += msg.common.val1;
    return msg.common.val1;
}

int Seek(int fd, int offset, int whence) {
    init_iolib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].is_used) return ERROR;

    yfs_msg_t msg;
    memset(&msg, 0, sizeof(msg));
    msg.common.type = YFS_SEEK;
    msg.common.inum = fd_table[fd].inum;
    msg.common.reuse = fd_table[fd].reuse;
    msg.common.val1 = offset;
    msg.common.val2 = whence;
    msg.common.val3 = fd_table[fd].pos; /* Send current pos just in case */

    if (Send(&msg, -FILE_SERVER) == ERROR) return ERROR;

    if (msg.common.type == ERROR) return ERROR;

    fd_table[fd].pos = msg.common.val1;
    return msg.common.val1;
}

