+static int alloc_inode() {
+    int i;
+    for (i = 1; i <= NUM_INODES; i++) {
+        if (!get_bit(inode_bitmap, i, 1024)) {
+            set_bit(inode_bitmap, i, 1024);
+            struct cache_inode *ci = get_inode(i);
+            if (ci) { ci->inode.reuse++; ci->dirty = 1; return i; }
+        }
+    }
+    return ERROR;
+}
+
+static void free_inode(int inum) {
+    if (inum <= 0 || inum > NUM_INODES) return;
+    struct cache_inode *ci = get_inode(inum);
+    if (ci) { ci->inode.type = INODE_FREE; ci->dirty = 1; }
+    clear_bit(inode_bitmap, inum, 1024);
+}
+
+static int alloc_block() {
+    int i;
+    for (i = FIRST_DATA_BLOCK; i < NUM_BLOCKS; i++) {
+        if (!get_bit(block_bitmap, i, NUMSECTORS)) {
+            set_bit(block_bitmap, i, NUMSECTORS);
+            struct cache_block *cb = get_block(i);
+            if (cb) { memset(cb->data, 0, BLOCKSIZE); cb->dirty = 1; return i; }
+        }
+    }
+    return ERROR;
+}
+
+static void free_block(int blocknum) {
+    if (blocknum < FIRST_DATA_BLOCK || blocknum >= NUM_BLOCKS) return;
+    clear_bit(block_bitmap, blocknum, NUMSECTORS);
+}
