+static int resolve_symlink(int pid, int dir_inum, int sym_inum, int depth) {
+    if (depth >= MAXSYMLINKS) return ERROR;
+    struct cache_inode *ci = get_inode(sym_inum);
+    if (!ci || ci->inode.type != INODE_SYMLINK) return ERROR;
+    char target[MAXPATHNAMELEN]; int to_read = ci->inode.size, br = 0;
+    if (to_read >= MAXPATHNAMELEN) to_read = MAXPATHNAMELEN - 1;
+    while (br < to_read) {
+        int bnum = get_block_for_offset(ci, br, 0), off = br % BLOCKSIZE, n = BLOCKSIZE - off;
+        if (bnum <= 0) break;
+        if (n > to_read - br) n = to_read - br;
+        struct cache_block *cb = get_block(bnum);
+        if (!cb) break;
+        memcpy(target + br, cb->data + off, n); br += n;
+    }
+    target[br] = '\0';
+    return resolve_path_internal(pid, dir_inum, target, NULL, NULL, depth + 1, 1);
+}
+
+static int resolve_path_internal(int pid, int curr_dir_inum, char *path, int *parent_inum, char *last_component, int depth, int follow) {
+    if (path == NULL || path[0] == '\0') return ERROR;
+    int inum = (path[0] == '/') ? ROOTINODE : curr_dir_inum;
+    if (parent_inum) *parent_inum = inum;
+    if (last_component) strcpy(last_component, ".");
+    char path_copy[MAXPATHNAMELEN]; strncpy(path_copy, path, MAXPATHNAMELEN); path_copy[MAXPATHNAMELEN-1] = '\0';
+    char *curr = path_copy; while (*curr == '/') curr++;
+    while (*curr != '\0') {
+        char *next = strchr(curr, '/'); if (next) *next = '\0';
+        if (parent_inum) *parent_inum = inum;
+        if (last_component) { strncpy(last_component, curr, DIRNAMELEN); if (strlen(curr) < DIRNAMELEN) last_component[strlen(curr)] = '\0'; }
+        int next_inum = find_in_dir(inum, curr, strlen(curr));
+        if (!next_inum) {
+            char *p = next ? next + 1 : NULL; while (p && *p == '/') p++;
+            if (next == NULL || p == NULL || *p == '\0') return 0;
+            return ERROR;
+        }
+        struct cache_inode *next_ci = get_inode(next_inum);
+        if (next_ci && next_ci->inode.type == INODE_SYMLINK) {
+            int is_last = (next == NULL); if (!is_last) { char *p = next + 1; while (*p == '/') p++; if (*p == '\0') is_last = 1; }
+            if (!is_last || follow) { next_inum = resolve_symlink(pid, inum, next_inum, depth); if (next_inum == ERROR) return ERROR; }
+        }
+        if (next != NULL) {
+            char *p = next + 1; while (*p == '/') p++;
+            if (*p != '\0') {
+                struct cache_inode *ci = get_inode(next_inum);
+                if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;
+                inum = next_inum; curr = p;
+            } else { inum = next_inum; break; }
+        } else { inum = next_inum; break; }
+    }
+    return inum;
+}
+
+static int resolve_path(int pid, int curr_dir_inum, char *path, int path_len, int *parent_inum, char *last_component, int follow) {
+    if (path_len <= 0 || path_len >= MAXPATHNAMELEN) return ERROR;
+    char local_path[MAXPATHNAMELEN]; if (CopyFrom(pid, local_path, path, path_len) == ERROR) return ERROR;
+    local_path[path_len] = '\0';
+    char cp[MAXPATHNAMELEN]; strcpy(cp, local_path); char *c = strtok(cp, "/");
+    while (c) { if (strlen(c) > DIRNAMELEN) return ERROR; c = strtok(NULL, "/"); }
+    if (path_len > 1 && local_path[path_len-1] == '/') {
+        if (path_len + 1 < MAXPATHNAMELEN) { local_path[path_len] = '.'; local_path[path_len+1] = '\0'; }
+    }
+    return resolve_path_internal(pid, curr_dir_inum, local_path, parent_inum, last_component, 0, follow);
+}
+
+static void truncate_inode(struct cache_inode *ci) {
+    int i, j;
+    for (i = 0; i < NUM_DIRECT; i++) { if (ci->inode.direct[i] != 0) { free_block(ci->inode.direct[i]); ci->inode.direct[i] = 0; } }
+    if (ci->inode.indirect != 0) {
+        struct cache_block *cb = get_block(ci->inode.indirect);
+        if (cb) {
+            int *ind = (int *)cb->data;
+            for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) if (ind[j] != 0) free_block(ind[j]);
+        }
+        free_block(ci->inode.indirect); ci->inode.indirect = 0;
+    }
+    ci->inode.size = 0; ci->dirty = 1;
+}
+
+static int add_to_dir(int dir_inum, int inum, char *name) {
+    struct cache_inode *ci = get_inode(dir_inum); if (!ci || ci->inode.type != INODE_DIRECTORY) return ERROR;
+    int num_entries = ci->inode.size / sizeof(struct dir_entry), i, found_free = 0, target_block = 0, target_offset = 0;
+    for (i = 0; i < num_entries; i++) {
+        int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
+        if (b_idx < NUM_DIRECT) bnum = ci->inode.direct[b_idx];
+        else if (ci->inode.indirect != 0) {
+            struct cache_block *icb = get_block(ci->inode.indirect);
+            if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT];
+        }
+        if (bnum == 0) continue;
+        struct cache_block *cb = get_block(bnum); if (!cb) continue;
+        struct dir_entry *de = (struct dir_entry *)(cb->data + off);
+        if (de->inum == 0) { found_free = 1; target_block = bnum; target_offset = off; break; }
+    }
+    if (!found_free) {
+        int b_idx = (num_entries * sizeof(struct dir_entry)) / BLOCKSIZE, off = (num_entries * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
+        if (b_idx < NUM_DIRECT) {
+            if (ci->inode.direct[b_idx] == 0) { ci->inode.direct[b_idx] = alloc_block(); if (ci->inode.direct[b_idx] == ERROR) return ERROR; }
+            bnum = ci->inode.direct[b_idx];
+        } else {
+            if (ci->inode.indirect == 0) { ci->inode.indirect = alloc_block(); if (ci->inode.indirect == ERROR) return ERROR; }
