+        if (b_idx < NUM_DIRECT) bnum = ci->inode.direct[b_idx];
+        else if (ci->inode.indirect != 0) {
+            struct cache_block *icb = get_block(ci->inode.indirect);
+            if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT];
+        }
+        if (bnum == 0) continue;
+        struct cache_block *cb = get_block(bnum); if (!cb) continue;
+        struct dir_entry *de = (struct dir_entry *)(cb->data + off);
+        if (de->inum != 0 && !is_dot(de->name) && !is_dotdot(de->name)) return 0;
