+}
+
+static void handle_open(int pid, yfs_msg_t *msg) {
+    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, NULL, NULL, 1);
+    if (inum <= 0) msg->common.type = ERROR;
+    else { struct cache_inode *ci = get_inode(inum); if (!ci) msg->common.type = ERROR; else { msg->common.inum = inum; msg->common.reuse = ci->inode.reuse; msg->common.val2 = (ci->inode.type == INODE_DIRECTORY); } }
