+        struct cache_inode *pci = get_inode(p_inum);
+        if (!pci || pci->inode.type != INODE_DIRECTORY) msg->common.type = ERROR;
+        else {
+            int new_inum = alloc_inode();
+            if (new_inum == ERROR) msg->common.type = ERROR;
