+                int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
+                if (b_idx < NUM_DIRECT) bnum = pci->inode.direct[b_idx];
+                else if (pci->inode.indirect != 0) { struct cache_block *icb = get_block(pci->inode.indirect); if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT]; }
+                if (bnum == 0) continue;
+                struct cache_block *cb = get_block(bnum); if (!cb) continue;
+                struct dir_entry *de = (struct dir_entry *)(cb->data + off); if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
+            }
+            pci->inode.nlink--; pci->dirty = 1; truncate_inode(ci); free_inode(inum);
+        }
+    }
+    Reply(msg, pid);
+}
+
+static void handle_link(int pid, yfs_msg_t *msg) {
+    int old_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
+    if (old_inum <= 0) msg->two_ptr.type = ERROR;
+    else {
+        struct cache_inode *oci = get_inode(old_inum);
+        if (!oci || oci->inode.type == INODE_DIRECTORY) msg->two_ptr.type = ERROR;
+        else {
+            int p_inum; char last[DIRNAMELEN + 1];
+            int n_inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
+            if (n_inum != 0) msg->two_ptr.type = ERROR;
+            else { if (add_to_dir(p_inum, old_inum, last) == ERROR) msg->two_ptr.type = ERROR; else { oci->inode.nlink++; oci->dirty = 1; } }
+        }
+    }
+    Reply(msg, pid);
+}
+
+static void handle_unlink(int pid, yfs_msg_t *msg) {
+    int p_inum; char last[DIRNAMELEN + 1];
+    int inum = resolve_path(pid, msg->common.inum, (char *)msg->common.ptr1, msg->common.val1, &p_inum, last, 0);
+    if (inum <= 0) msg->common.type = ERROR;
+    else {
+        struct cache_inode *ci = get_inode(inum);
+        if (!ci || ci->inode.type == INODE_DIRECTORY) msg->common.type = ERROR;
+        else {
+            struct cache_inode *pci = get_inode(p_inum); if (!pci) { msg->common.type = ERROR; Reply(msg, pid); return; }
+            int num = pci->inode.size / sizeof(struct dir_entry), i;
+            for (i = 0; i < num; i++) {
+                int b_idx = (i * sizeof(struct dir_entry)) / BLOCKSIZE, off = (i * sizeof(struct dir_entry)) % BLOCKSIZE, bnum = 0;
+                if (b_idx < NUM_DIRECT) bnum = pci->inode.direct[b_idx];
+                else if (pci->inode.indirect != 0) { struct cache_block *icb = get_block(pci->inode.indirect); if (icb) bnum = ((int *)icb->data)[b_idx - NUM_DIRECT]; }
+                if (bnum == 0) continue;
+                struct cache_block *cb = get_block(bnum); if (!cb) continue;
+                struct dir_entry *de = (struct dir_entry *)(cb->data + off); if (de->inum == inum) { de->inum = 0; cb->dirty = 1; break; }
+            }
+            ci->inode.nlink--; ci->dirty = 1; if (ci->inode.nlink == 0) { truncate_inode(ci); free_inode(inum); }
+        }
+    }
+    Reply(msg, pid);
+}
+
+static void handle_symlink(int pid, yfs_msg_t *msg) {
+    int p_inum; char last[DIRNAMELEN + 1];
+    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr2, msg->two_ptr.val2, &p_inum, last, 0);
+    if (inum != 0) msg->two_ptr.type = ERROR;
+    else {
+        int new_inum = alloc_inode();
+        if (new_inum == ERROR) msg->two_ptr.type = ERROR;
+        else {
+            struct cache_inode *nci = get_inode(new_inum);
+            nci->inode.type = INODE_SYMLINK; nci->inode.nlink = 1; nci->inode.size = msg->two_ptr.val1;
+            memset(nci->inode.direct, 0, sizeof(nci->inode.direct)); nci->inode.indirect = 0; nci->dirty = 1;
+            char target[MAXPATHNAMELEN]; CopyFrom(pid, target, msg->two_ptr.ptr1, msg->two_ptr.val1);
+            int bw = 0;
+            while (bw < (int)msg->two_ptr.val1) {
+                int bnum = get_block_for_offset(nci, bw, 1), off = bw % BLOCKSIZE, tw = BLOCKSIZE - off;
+                if (bnum <= 0) break;
+                if (tw > (int)msg->two_ptr.val1 - bw) tw = msg->two_ptr.val1 - bw;
+                struct cache_block *cb = get_block(bnum); if (!cb) break;
+                memcpy(cb->data + off, target + bw, tw); cb->dirty = 1; bw += tw;
+            }
+            if (add_to_dir(p_inum, new_inum, last) == ERROR) { truncate_inode(nci); free_inode(new_inum); msg->two_ptr.type = ERROR; }
+        }
+    }
+    Reply(msg, pid);
+}
+
+static void handle_readlink(int pid, yfs_msg_t *msg) {
+    int inum = resolve_path(pid, msg->two_ptr.inum, (char *)msg->two_ptr.ptr1, msg->two_ptr.val1, NULL, NULL, 0);
+    if (inum <= 0) msg->two_ptr.type = ERROR;
+    else {
+        struct cache_inode *ci = get_inode(inum);
+        if (!ci || ci->inode.type != INODE_SYMLINK) msg->two_ptr.type = ERROR;
+        else {
+            int tr = ci->inode.size; if (tr > msg->two_ptr.val2) tr = msg->two_ptr.val2;
+            char target[MAXPATHNAMELEN]; int br = 0;
+            while (br < tr) {
+                int bnum = get_block_for_offset(ci, br, 0), off = br % BLOCKSIZE, n = BLOCKSIZE - off;
+                if (bnum <= 0) break;
+                if (n > tr - br) n = tr - br;
+                struct cache_block *cb = get_block(bnum); if (!cb) break;
+                memcpy(target + br, cb->data + off, n); br += n;
+            }
+            if (CopyTo(pid, msg->two_ptr.ptr2, target, tr) == ERROR) msg->two_ptr.type = ERROR;
+            else msg->two_ptr.val1 = tr;
+        }
+    }
+    Reply(msg, pid);
+}
+
+int main(int argc, char **argv) {
+    char buf[SECTORSIZE]; if (ReadSector(1, buf) == ERROR) Exit(1);
+    struct fs_header *header = (struct fs_header *)buf;
+    NUM_BLOCKS = header->num_blocks; NUM_INODES = header->num_inodes;
+    FIRST_DATA_BLOCK = 1 + (NUM_INODES / INODES_PER_BLOCK + 1);
+    init_cache(); memset(block_bitmap, 0, sizeof(block_bitmap)); memset(inode_bitmap, 0, sizeof(inode_bitmap));
+    int i, j;
+    for (i = 1; i <= NUM_INODES; i++) {
+        struct cache_inode *ci = get_inode(i);
+        if (ci && ci->inode.type != INODE_FREE) {
+            set_bit(inode_bitmap, i, 1024);
+            for (j = 0; j < NUM_DIRECT; j++) if (ci->inode.direct[j] != 0) set_bit(block_bitmap, ci->inode.direct[j], NUMSECTORS);
+            if (ci->inode.indirect != 0) {
+                set_bit(block_bitmap, ci->inode.indirect, NUMSECTORS);
+                struct cache_block *cb = get_block(ci->inode.indirect);
+                if (cb) {
+                    int *ind = (int *)cb->data;
+                    for (j = 0; j < (int)(BLOCKSIZE / sizeof(int)); j++) if (ind[j] != 0) set_bit(block_bitmap, ind[j], NUMSECTORS);
+                }
+            }
+        }
+    }
+    if (Register(FILE_SERVER) == ERROR) Exit(1);
+    if (argc > 1) { int pid = Fork(); if (pid == 0) { Exec(argv[1], argv + 1); Exit(1); } }
+    while (1) {
+        yfs_msg_t msg; int sender_pid = Receive(&msg); if (sender_pid <= 0) break;
+        switch (msg.common.type) {
+            case YFS_OPEN: handle_open(sender_pid, &msg); break;
+            case YFS_CREATE: handle_create(sender_pid, &msg); break;
+            case YFS_READ: handle_read(sender_pid, &msg); break;
+            case YFS_WRITE: handle_write(sender_pid, &msg); break;
+            case YFS_SEEK: handle_seek(sender_pid, &msg); break;
+            case YFS_LINK: handle_link(sender_pid, &msg); break;
+            case YFS_UNLINK: handle_unlink(sender_pid, &msg); break;
+            case YFS_SYMLINK: handle_symlink(sender_pid, &msg); break;
+            case YFS_READLINK: handle_readlink(sender_pid, &msg); break;
+            case YFS_MKDIR: handle_mkdir(sender_pid, &msg); break;
+            case YFS_RMDIR: handle_rmdir(sender_pid, &msg); break;
+            case YFS_CHDIR: handle_chdir(sender_pid, &msg); break;
+            case YFS_STAT: handle_stat(sender_pid, &msg); break;
+            case YFS_SYNC: sync_cache(); Reply(&msg, sender_pid); break;
+            case YFS_SHUTDOWN: sync_cache(); Reply(&msg, sender_pid); Exit(0);
+            default: msg.common.type = ERROR; Reply(&msg, sender_pid);
+        }
+    }
+    return 0;
+}
diff --git a/yfs.h b/yfs.h
new file mode 100644
index 0000000..cbc1838
--- /dev/null
+++ b/yfs.h
@@ -0,0 +1,85 @@
+#ifndef _YFS_H_
+#define _YFS_H_
+
+#include <comp421/filesystem.h>
+#include <comp421/iolib.h>
+
+#define YFS_OPEN        1
+#define YFS_CLOSE       2
+#define YFS_CREATE      3
+#define YFS_READ        4
+#define YFS_WRITE       5
+#define YFS_SEEK        6
+#define YFS_LINK        7
+#define YFS_UNLINK      8
+#define YFS_SYMLINK     9
+#define YFS_READLINK    10
+#define YFS_MKDIR       11
+#define YFS_RMDIR       12
+#define YFS_CHDIR       13
+#define YFS_STAT        14
+#define YFS_SYNC        15
+#define YFS_SHUTDOWN    16
+
+#define INODES_PER_BLOCK (BLOCKSIZE / INODESIZE)
+
+struct yfs_msg {
+    int type;
+    int inum;
+    int reuse;
+    int val1;
+    int val2;
+    void *ptr1;
+    void *ptr2;
+};
+/* 
+ * Wait, the above struct is:
+ * type (4) + inum (4) + reuse (4) + val1 (4) + val2 (4) + ptr1 (8) + ptr2 (8) = 36 bytes.
+ * Still too big. Let's optimize.
+ */
+
+struct yfs_request {
+    int type;
+    int inum;           /* Also used for curr_dir_inum or fd in some cases */
+    int reuse;
+    int val1;           /* size, path_len, offset, whence, etc. */
+    int val2;           /* path2_len, etc. */
+    void *ptr1;         /* pathname, buffer, etc. */
+    /* 4 + 4 + 4 + 4 + 4 + 8 = 28 bytes. 4 more to reach 32. */
+    int pad;
+};
+
+/* Let's try another one for two-pointer ops like Link */
+struct yfs_request_2ptr {
+    int type;
+    int inum;
+    int val1;
+    int val2;
+    void *ptr1;
+    void *ptr2;
+};
+/* 4 + 4 + 4 + 4 + 8 + 8 = 32 bytes! This is perfect. */
+
+/* Union to hold different request types */
+typedef union {
+    struct {
+        int type;
+        int inum;
+        int reuse;
+        int val1;
+        int val2;
+        int val3;
+        void *ptr1;
+    } common;
+    struct {
+        int type;
+        int inum;
+        int val1;
+        int val2;
+        void *ptr1;
+        void *ptr2;
+    } two_ptr;
+    char padding[32];
+} yfs_msg_t;
+
+#endif /* _YFS_H_ */
